import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../../utils/api';
import { useAuth } from '../../context/AuthContext';

export default function StudentDashboard() {
  const { user } = useAuth();
  const [memberships, setMemberships] = useState([]);
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [mRes, eRes] = await Promise.all([
          api.get('/memberships/my'),
          api.get('/events?status=published&limit=6'),
        ]);
        setMemberships(mRes.data.data || []);
        setEvents(eRes.data.data || []);
      } catch { toast.error('Failed to load data'); }
      finally { setLoading(false); }
    };
    fetchData();
  }, []);

  const approved = memberships.filter(m => m.status === 'approved');
  const pending = memberships.filter(m => m.status === 'pending');

  if (loading) return <div className="loading-screen"><div className="spinner" /></div>;

  return (
    <div className="page-wrapper">
      <div className="container">
        <div className="page-header">
          <div className="flex-between">
            <div>
              <h2 style={{ fontFamily: 'var(--font-display)', marginBottom: 4 }}>
                STUDENT <span className="gradient-text">PORTAL</span>
              </h2>
              <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem' }}>
                Welcome, {user?.name} · <span style={{ fontFamily: 'var(--font-mono)', color: 'var(--cyan-accent)' }}>{user?.itNumber}</span>
              </p>
            </div>
            <div style={{ display: 'flex', gap: 10 }}>
              <Link to="/clubs" className="btn btn-primary">Explore Clubs</Link>
              <Link to="/student/profile" className="btn btn-outline">My Profile</Link>
            </div>
          </div>
        </div>

        {/* Stats */}
        <div className="grid grid-4" style={{ marginBottom: 40 }}>
          {[
            { label: 'My Communities', value: approved.length, color: 'var(--purple-light)' },
            { label: 'Pending Requests', value: pending.length, color: 'var(--warning)' },
            { label: 'Open Events', value: events.length, color: 'var(--cyan-accent)' },
            { label: 'IT Number', value: '✓', color: 'var(--success)' },
          ].map((s, i) => (
            <div key={i} className="stat-card">
              <div className="stat-value" style={{ color: s.color }}>{s.value}</div>
              <div className="stat-label">{s.label}</div>
            </div>
          ))}
        </div>

        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 28 }}>
          {/* My Communities */}
          <div>
            <div className="flex-between" style={{ marginBottom: 16 }}>
              <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.2rem' }}>My Communities</h3>
              <Link to="/clubs" style={{ fontSize: '0.78rem', color: 'var(--text-muted)' }}>Browse More →</Link>
            </div>

            {memberships.length === 0 ? (
              <div className="card">
                <div className="empty-state">
                  <div className="empty-state-icon">🏛️</div>
                  <div className="empty-state-text">You haven't joined any communities yet</div>
                  <Link to="/clubs" className="btn btn-primary btn-sm" style={{ marginTop: 14 }}>Browse Communities</Link>
                </div>
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
                {memberships.map(m => (
                  <div key={m._id} className="card" style={{ padding: '14px 18px' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                      <div className="avatar" style={{ borderRadius: 8 }}>{m.community?.name?.charAt(0)}</div>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontWeight: 600, fontSize: '0.875rem' }}>{m.community?.name}</div>
                        <span className={`badge badge-${m.community?.category?.toLowerCase()}`} style={{ marginTop: 4 }}>{m.community?.category}</span>
                      </div>
                      <span className={`badge badge-${m.status}`}>{m.status}</span>
                    </div>
                    {m.status === 'pending' && (
                      <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginTop: 8 }}>
                        ⏳ Waiting for Community Admin approval
                      </p>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Upcoming Events */}
          <div>
            <div className="flex-between" style={{ marginBottom: 16 }}>
              <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.2rem' }}>Upcoming Events</h3>
              <Link to="/events" style={{ fontSize: '0.78rem', color: 'var(--text-muted)' }}>All Events →</Link>
            </div>

            {events.length === 0 ? (
              <div className="card">
                <div className="empty-state">
                  <div className="empty-state-icon">📅</div>
                  <div className="empty-state-text">No events available</div>
                </div>
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
                {events.slice(0, 5).map(ev => (
                  <Link key={ev._id} to={`/events/${ev._id}`} style={{ textDecoration: 'none' }}>
                    <div className="card" style={{ padding: '14px 18px', cursor: 'pointer' }}>
                      <div className="flex-between">
                        <div style={{ fontWeight: 600, fontSize: '0.875rem', color: 'white' }}>{ev.title}</div>
                        <span className={`badge badge-${ev.category?.toLowerCase()}`}>{ev.category}</span>
                      </div>
                      <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginTop: 6 }}>
                        📅 {new Date(ev.startDate).toLocaleDateString()} · {ev.community?.name}
                      </div>
                    </div>
                  </Link>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
